import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Eye, EyeOff, Mail, Lock, User } from 'lucide-react';
import './Auth.css';

const demoCredentials = {
  admin: { email: 'admin@dulceria.com', password: '123456' },
  cliente: { email: 'maria@dulceria.com', password: '123456' },
  vendor: { email: 'laura@dulceria.com', password: '123456' },
};

export default function AuthPage() {
  const { login, register } = useApp();
  const [mode, setMode] = useState('login');
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [role, setRole] = useState('cliente');
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const handle = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const submit = (e) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');

    if (mode === 'login') {
      const res = login(form.email, form.password);
      if (res.error) setError(res.error);
      return;
    }

    if (mode === 'register') {
      if (!form.name.trim()) {
        setError('El nombre es requerido.');
        return;
      }

      const res = register(form.name, form.email, form.password, role);
      if (res.error) setError(res.error);
      return;
    }

    setSuccessMsg('Si el correo existe, recibirás instrucciones para restablecer tu contraseña.');
  };

  const demo = (accountRole) => {
    const credentials = demoCredentials[accountRole];
    login(credentials.email, credentials.password);
  };

  const resetMessages = () => {
    setError('');
    setSuccessMsg('');
  };

  return (
    <div className="auth-page">
      <section className="auth-showcase">
        <div className="auth-showcase__overlay" />
        <div className="auth-showcase__content">
          <h1>Dulcería El Suspiro</h1>
          <p>
            Una dulcería tradicional, con un dulce para cada uno. Visítanos y encuentra el tuyo.
            Contáctanos al 0997880280 o al 2839541.
          </p>
          <div className="auth-showcase__pills">
            <span>Quesitos de manjar</span>
            <span> Chocolates negro y blanco artesanal</span>
            <span> Enrrollados de manjar</span>
          </div>
        </div>
      </section>

      <section className="auth-panel">
        <div className="auth-card">
          <div className="auth-card__brand">
            <img src={process.env.PUBLIC_URL + '/img/dulces/logo.jpg'} alt="Dulcería El Suspiro" />
          </div>

          <h2>
            {mode === 'login' ? 'Bienvenido de vuelta' : mode === 'register' ? 'Crear cuenta' : 'Recuperar contraseña'}
          </h2>
          <p className="auth-card__subtitle">
            {mode === 'login'
              ? 'Inicia sesión para hacer tus pedidos'
              : mode === 'register'
                ? 'Regístrate para comenzar a pedir'
                : 'Ingresa tu correo y te enviaremos instrucciones'}
          </p>

          <div className="auth-tabs" role="tablist" aria-label="Acceso">
            <button type="button" className={mode === 'login' ? 'is-active' : ''} onClick={() => { setMode('login'); resetMessages(); }}>
              Ingreso
            </button>
            <button type="button" className={mode === 'register' ? 'is-active' : ''} onClick={() => { setMode('register'); resetMessages(); }}>
              Registro
            </button>
          </div>

          {error && <div className="auth-alert auth-alert--error">{error}</div>}
          {successMsg && <div className="auth-alert auth-alert--success">{successMsg}</div>}

          <form onSubmit={submit} className="auth-form">
            {mode === 'register' && (
              <div className="auth-field">
                <label>Nombre completo</label>
                <div className="auth-inputWrap">
                  <User size={16} />
                  <input name="name" type="text" placeholder="Tu nombre" value={form.name} onChange={handle} required />
                </div>
              </div>
            )}

            {mode === 'register' && (
              <div className="auth-field">
                <label>Tipo de cuenta</label>
                <div className="auth-inputWrap">
                  <select value={role} onChange={(e) => setRole(e.target.value)}>
                    <option value="cliente">Cliente</option>
                    <option value="vendor">Vendedor</option>
                  </select>
                </div>
              </div>
            )}

            <div className="auth-field">
              <label>Correo electrónico</label>
              <div className="auth-inputWrap">
                <Mail size={16} />
                <input
                  name="email"
                  type="email"
                  placeholder="correo@ejemplo.com"
                  value={form.email}
                  onChange={handle}
                  required
                />
              </div>
            </div>

            {mode !== 'forgot' && (
              <div className="auth-field">
                <div className="auth-field__row">
                  <label>Contraseña</label>
                  {mode === 'login' && (
                    <button type="button" className="auth-linkButton" onClick={() => { setMode('forgot'); resetMessages(); }}>
                      ¿Olvidaste tu contraseña?
                    </button>
                  )}
                </div>
                <div className="auth-inputWrap">
                  <Lock size={16} />
                  <input
                    name="password"
                    type={showPass ? 'text' : 'password'}
                    placeholder="••••••••"
                    value={form.password}
                    onChange={handle}
                    required
                  />
                  <button type="button" className="auth-eyeButton" onClick={() => setShowPass(!showPass)} aria-label={showPass ? 'Ocultar contraseña' : 'Mostrar contraseña'}>
                    {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
                  </button>
                </div>
              </div>
            )}

            <button type="submit" className="auth-submit">
              {mode === 'login' ? 'Iniciar sesión' : mode === 'register' ? 'Crear cuenta' : 'Enviar instrucciones'}
            </button>
          </form>

          {mode === 'login' && (
            <>
              <div className="auth-divider"><span>o</span></div>
              <div className="auth-demo">
                <p>Acceso de demostración:</p>
                <div className="auth-demo__buttons">
                  <button type="button" onClick={() => demo('admin')}>🔑 Admin</button>
                  <button type="button" onClick={() => demo('cliente')}>👤 Cliente</button>
                  <button type="button" onClick={() => demo('vendor')}>🍬 Vendedor</button>
                </div>
                <small>Contraseña: 123456</small>
              </div>
            </>
          )}

          <div className="auth-switch">
            {mode === 'login' ? (
              <>¿No tienes cuenta? <button type="button" onClick={() => { setMode('register'); resetMessages(); }}>Regístrate</button></>
            ) : (
              <>¿Ya tienes cuenta? <button type="button" onClick={() => { setMode('login'); resetMessages(); }}>Inicia sesión</button></>
            )}
          </div>
        </div>
      </section>
    </div>
  );
}
